using System.ComponentModel;
using System.Text;
using System.Text.Json;
using Microsoft.Extensions.Logging;
using ModelContextProtocol.Server;

/// <summary>
/// MCP tools that wrap a REST API using HttpClient.
/// Non-static class — the SDK creates an instance per request and injects DI services
/// via the constructor. HttpClient and ILogger are resolved automatically.
/// </summary>
[McpServerToolType]
internal class ApiTools(HttpClient httpClient, ILogger<ApiTools> logger)
{
    [McpServerTool, Description("List all items from the API. Returns a JSON array.")]
    public async Task<string> ListItems(CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Listing all items");
        return await httpClient.GetStringAsync("/items", cancellationToken);
    }

    [McpServerTool, Description("Get a single item by its unique identifier.")]
    public async Task<string> GetItem(
        [Description("The unique ID of the item to retrieve")] string id,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Getting item {Id}", id);
        var response = await httpClient.GetAsync($"/items/{id}", cancellationToken);
        response.EnsureSuccessStatusCode();
        return await response.Content.ReadAsStringAsync(cancellationToken);
    }

    [McpServerTool, Description("Create a new item. Returns the created item with its assigned ID.")]
    public async Task<string> CreateItem(
        [Description("Display name for the new item")] string name,
        [Description("Optional description of the item")] string? description = null,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Creating item {Name}", name);

        var payload = JsonSerializer.Serialize(new { name, description });
        var content = new StringContent(payload, Encoding.UTF8, "application/json");

        var response = await httpClient.PostAsync("/items", content, cancellationToken);
        response.EnsureSuccessStatusCode();
        return await response.Content.ReadAsStringAsync(cancellationToken);
    }

    [McpServerTool, Description("Delete an item by its unique identifier. Returns confirmation.")]
    public async Task<string> DeleteItem(
        [Description("The unique ID of the item to delete")] string id,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Deleting item {Id}", id);
        var response = await httpClient.DeleteAsync($"/items/{id}", cancellationToken);
        response.EnsureSuccessStatusCode();
        return $"Deleted item {id}";
    }
}

